import cv2import numpy as npimport matplotlib.pyplot as pltdef remove_ring_artifacts_cv2(image_path):    # 1. 读取图像    # 注意：如果是16位医学图像，请使用 cv2.IMREAD_UNCHANGED    img = cv2.imread(image_path, cv2.IMREAD_GRAYSCALE)    if img is None:        print("无法读取图片")        return    img = img.astype(np.float32)    rows, cols = img.shape    center = (cols // 2, rows // 2)    radius = min(rows, cols) // 2    # 2. 极坐标变换 (Cartesian -> Polar)    # 变换后的图像：横轴是半径，纵轴是角度    polar_img = cv2.warpPolar(img, (radius, 360), center, radius, cv2.WARP_POLAR_LINEAR)    # 3. 提取并过滤伪影    # 沿角度方向（纵轴，axis=0）取中值，得到伪影剖面    # 我们使用中值来代表这个半径上的“平均”背景    projection = np.median(polar_img, axis=0)    # 使用一维中值滤波平滑这个剖面，只保留缓慢变化的结构（解剖结构）    # 剖面减去平滑后的自己，剩下的就是突发的环状伪影（高频线条）    import scipy.ndimage as ndimage    smooth_projection = ndimage.median_filter(projection, size=20)  # size可调    rings_signal = projection - smooth_projection    # 4. 从极坐标图中减去伪影信号    # 将 rings_signal 广播到整个极坐标图    corrected_polar = polar_img - rings_signal[np.newaxis, :]    # 5. 逆极坐标变换 (Polar -> Cartesian)    # 使用 cv2.WARP_INVERSE_MAP 标志位回转    corrected_img = cv2.warpPolar(corrected_polar, (cols, rows), center, radius,                                  cv2.WARP_POLAR_LINEAR + cv2.WARP_INVERSE_MAP)    # 6. 显示结果    plt.figure(figsize=(12, 6))    plt.subplot(121), plt.imshow(img, cmap='gray'), plt.title('Original')    plt.subplot(122), plt.imshow(corrected_img, cmap='gray'), plt.title('Result')    plt.show()    return corrected_img# 调用remove_ring_artifacts_cv2(r"E:\project\Dataset\vital_data\202605252048rabbit\slice\zhou\202605252048rabbit_zhou_degree_0_xiongwin_56.png")